Функция НайтиДействующийДоговор(Контрагент, Дата) Экспорт
    // Проверка типа параметра
    Если НЕ ТипЗнч(Контрагент) = Справочник.Контрагенты Тогда
        Возврат Неопределено;
    КонецЕсли;

    Запрос = Новый Запрос;
    ТекстЗапроса = 
        "ВЫБРАТЬ ПЕРВЫЕ 1
        |   Договоры.Ссылка КАК Договор
        |ИЗ
        |   Справочник.Договоры КАК Договоры
        |ГДЕ
        |   Договоры.Владелец = &Контрагент
        |   И Договоры.ДатаНачала <= &Дата
        |   И (Договоры.ДатаОкончания >= &Дата ИЛИ Договоры.ДатаОкончания = &НеЗаполнено)
        |УПОРЯДОЧИТЬ ПО
        |   Договоры.ДатаНачала УБЫВ";
    Запрос.Текст = ТекстЗапроса;
    Запрос.УстановитьПараметр("Контрагент", Контрагент);
    Запрос.УстановитьПараметр("Дата", Дата);
    Запрос.УстановитьПараметр("НеЗаполнено", Неопределено);

    Выборка = Запрос.Выполнить().Выбрать();
    Если Выборка.Следующий() Тогда
        Возврат Выборка.Договор;
    Иначе
        Возврат Неопределено;
    КонецЕсли;
КонецФункции
